openscad:
case_dia = 40; // [20:1:80]
case_height = 8; // [4:0.5:15]
bezel_height = 2; // [1:0.5:5]
dial_dia = 34; // [15:1:70]
marker_len = 3; // [1:0.5:8]
marker_w = 1.2; // [0.5:0.1:3]
hand_thick = 1.5; // [0.8:0.1:3]
crown_dia = 5; // [3:0.5:10]
$fn = 60;

color("black")
cylinder(d=case_dia, h=case_height);

color("black")
translate([0,0,case_height])
difference() {
  cylinder(d=case_dia+4, h=bezel_height);
  cylinder(d=dial_dia+2, h=bezel_height+1);
}

color("white")
translate([0,0,case_height])
cylinder(d=dial_dia, h=1.2);

color("black")
for(i=[0:11]) {
  rotate([0,0,i*30])
  translate([0,dial_dia/2-marker_len/2-1.5,case_height+1.2])
  cube([marker_w,marker_len,1.2],center=true);
}

color("black")
translate([case_dia/2+1,0,case_height/2])
rotate([90,0,0])
cylinder(d=crown_dia,h=case_height+2,center=true);

color("black")
translate([0,0,case_height+2])
rotate([0,0,90])
linear_extrude(height=hand_thick)
polygon(points=[[0,0],[8,1.5],[10,0],[8,-1.5]]);

color("black")
translate([0,0,case_height+2.8])
rotate([0,0,0])
linear_extrude(height=hand_thick)
polygon(points=[[0,0],[14,1.2],[16,0],[14,-1.2]]);

color("black")
translate([0,0,case_height+3.6])
cylinder(d=3,h=1.5);
